async function* streamChat(client, cfg, messages, tools, signal) {
  const maxRetries = cfg.retryCount ?? 3;
  let lastError;
  for (let attempt = 1;attempt <= maxRetries; attempt++) {
    try {
      const stream = await client.chat.completions.create({
        model: cfg.model,
        messages: messages.map((m2) => {
          if (m2.role === "tool") {
            return {
              role: "tool",
              content: m2.content,
              tool_call_id: m2.tool_call_id
            };
          }
          if (m2.role === "assistant" && m2.tool_calls) {
            return {
              role: "assistant",
              content: m2.content,
              tool_calls: m2.tool_calls
            };
          }
          return { role: m2.role, content: m2.content };
        }),
        temperature: 0.2,
        max_tokens: 8192,
        tools: tools?.length ? tools : undefined,
        tool_choice: tools?.length ? "auto" : undefined,
        stream: true
      }, { signal });
      const toolCallBuffers = new Map;
      let finishReason;
      let usage;
      for await (const chunk of stream) {
        if (signal?.aborted)
          break;
        const choice = chunk.choices[0];
        const delta = choice?.delta;
        finishReason = choice?.finish_reason || finishReason;
        if (chunk.usage) {
          const u3 = chunk.usage;
          usage = {
            input_tokens: u3.prompt_tokens,
            output_tokens: u3.completion_tokens
          };
        }
        if (!delta)
          continue;
        if (delta.tool_calls) {
          for (const tc of delta.tool_calls) {
            const idx = tc.index ?? 0;
            let buf = toolCallBuffers.get(idx);
            if (!buf) {
              buf = { id: tc.id || "", name: tc.function?.name || "", args: "" };
              toolCallBuffers.set(idx, buf);
            }
            if (tc.function?.name)
              buf.name = tc.function.name;
            if (tc.function?.arguments)
              buf.args += tc.function.arguments;
          }
        }
        const content = delta.content || "";
        const completeToolCalls = [];
        for (const buf of toolCallBuffers.values()) {
          if (buf.id && buf.name) {
            completeToolCalls.push({ id: buf.id, name: buf.name, arguments: buf.args });
          }
        }
        yield {
          content,
          toolCalls: completeToolCalls.length > 0 ? completeToolCalls : undefined,
          finishReason
        };
      }
      return { usage };
    } catch (err) {
      const status = err?.status || err?.status_code || err?.response?.status;
      lastError = err;
      if (!shouldRetry(status)) {
        throw new Error(errorMessage(status, attempt));
      }
      const message = errorMessage(status, attempt);
      if (attempt === maxRetries) {
        throw new Error(message);
      }
      const delay = Math.pow(2, attempt - 1) * 1000;
      await new Promise((res) => setTimeout(res, delay));
    }
  }
  throw lastError || new Error("Unknown error");
}

